import Layout from '../components/layout';
import {graphql, useStaticQuery} from 'gatsby';
import * as React from 'react';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import CardMedia from '@mui/material/CardMedia';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Paper from '@mui/material/Paper';
import {CardActionArea} from '@mui/material';
import Grid from '@mui/material/Unstable_Grid2';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Link from '@mui/material/Link';
import Seo from '../components/seo';

/**
 * @type {type:string,productList:[]}
 */
const ProductList = ({type, productList}) => {
  const list = productList.filter(
      item => item && item.productType && item.productType.id === type);

  return <Box sx={{flexGrow: 1, pt: 2, pb: 2, ml: 2, mr: 2}}>

    <Grid container spacing={0.5} columns={{xs: 4, sm: 8, md: 12}}>
      {list.map((item, index) => (
          <Grid xs={2} sm={4} md={2} key={index}>
            <Card onClick={() => window.location.href = `/product/${item.id}`}
                  sx={{maxWidth: 320}}>
              <CardActionArea>
                <CardMedia
                    component="img"
                    height="250"
                    sx={{objectFit: 'cover'}}
                    image={`${item.image.localFile.publicURL}`}
                    alt="green iguana"
                />
                <CardContent>

                  <Typography align="center" variant="body2" sx={{
                    marginTop: '5px',
                    marginBottom: '5px',
                  }}>{item.title}</Typography>
                  <Divider sx={{marginBottom: '8px'}}/>
                  <div>
                    <Link style={{textDecoration: `none`}}
                          href={`/product/${item.id}`}>查看详情</Link>
                  </div>
                </CardContent>
              </CardActionArea>

            </Card>
          </Grid>
      ))}
    </Grid>
  </Box>;

};
const ProductPage = () => {
  const {allStrapiProduct, allStrapiProductType} = useStaticQuery(graphql`
 query ProductAndTypeQuery {
  allStrapiProductType {
    nodes {
      id
      name
    }
  }
  allStrapiProduct {
    nodes {
      productType {
        name
        id
      }
      id
      title
      image {
        localFile {
          publicURL
        }
      }
    }
  }
}
  `);

  const [value, setValue] = React.useState(allStrapiProductType.nodes[0]?.id);

  const handleChange = (event, newValue) => {
    setValue(newValue);

  };

  return <Layout>
    <Box sx={{mt: 1}}>
      <Paper elevation={2} sx={{md: {my: 2, mx: 2}, mr: 2, ml: 2}}>
        <Breadcrumbs sx={{pt: 2, pb: 4, pl: 2, pr: 2}} aria-label="breadcrumb">
          <Link underline="hover" color="inherit" href="/">
            首页
          </Link>
          <Typography color="text.primary">产品中心</Typography>
        </Breadcrumbs>
        <Tabs
            value={value}
            onChange={handleChange}
            variant="scrollable"
            scrollButtons
            allowScrollButtonsMobile
            aria-label="scrollable force tabs example"
        >
          {allStrapiProductType.nodes.map((item, index) => {
            return <Tab key={item.id} value={item.id} label={item.name}/>;
          })}
        </Tabs>
        <Divider/>
        <ProductList type={value}
                     productList={allStrapiProduct.nodes}></ProductList>
      </Paper>
    </Box>
  </Layout>;
};

export const Head = () => <Seo title="产品列表"/>;
export default ProductPage;
